import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Часто задаваемые вопросы для игроков","description":"Ответы на часто задаваемые вопросы касательно Fabric, поступающие от игроков и администраторов серверов.","frontmatter":{"title":"Часто задаваемые вопросы для игроков","description":"Ответы на часто задаваемые вопросы касательно Fabric, поступающие от игроков и администраторов серверов.","search":false,"files":[]},"headers":[],"relativePath":"ru_ru/1.20.4/players/faq.md","filePath":"versions/1.20.4/translated/ru_ru/players/faq.md","lastUpdated":1739538073000}`);var a={name:`ru_ru/1.20.4/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Часто задаваемые вопросы для игроков <a class="header-anchor" href="#h1" aria-label="Permalink to “Часто задаваемые вопросы для игроков”">​</a></h1><p>Есть множество вопросов, которые часто задают, поэтому мы составили их список здесь.</p><h2 id="общие-вопросы" tabindex="-1">Общие вопросы <a class="header-anchor" href="#общие-вопросы" aria-label="Permalink to “Общие вопросы”">​</a></h2><h3 id="какие-версии-minecraft-поддерживает-fabric" tabindex="-1">Какие версии Minecraft поддерживает Fabric? <a class="header-anchor" href="#какие-версии-minecraft-поддерживает-fabric" aria-label="Permalink to “Какие версии Minecraft поддерживает Fabric?”">​</a></h3><p>Официально Fabric поддерживает все версии Minecraft, начиная со снапшотов <code>18w43b</code> и выше, а также с версии <code>1.14</code> и выше.</p><h3 id="где-я-могу-скачать-моды-для-fabric" tabindex="-1">Где я могу скачать моды для Fabric? <a class="header-anchor" href="#где-я-могу-скачать-моды-для-fabric" aria-label="Permalink to “Где я могу скачать моды для Fabric?”">​</a></h3><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Вы всегда должны проверять, скачиваете ли вы моды из надежного источника. Смотрите гайд <a href="./finding-mods">Поиск безопасных модов</a> для большей информации.</p></div><p>Большинство авторов публикуют свои моды на <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> и <a href="https://www.curseforge.com/minecraft/search?class=mc-mods&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a>, однако некоторые авторы загружают их на свои личные сайты или на другие платформы, такие как репозиторий GitHub.</p><h3 id="где-я-могу-наити-готовые-модпаки-для-fabric" tabindex="-1">Где я могу найти готовые модпаки для Fabric? <a class="header-anchor" href="#где-я-могу-наити-готовые-модпаки-для-fabric" aria-label="Permalink to “Где я могу найти готовые модпаки для Fabric?”">​</a></h3><p>Вы можете найти готовые модпаки для Fabric на различных платформах, таких как:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,11)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};